  createSDKSession(contentSessionId, project, userPrompt, customTitle) {
    const now = new Date;
    const nowEpoch = now.getTime();
    const existing = this.db.prepare(`
      SELECT id FROM sdk_sessions WHERE content_session_id = ?
    `).get(contentSessionId);
    if (existing) {
      if (project) {
        this.db.prepare(`
          UPDATE sdk_sessions SET project = ?
          WHERE content_session_id = ? AND (project IS NULL OR project = '')
        `).run(project, contentSessionId);
      }
      if (customTitle) {
        this.db.prepare(`
          UPDATE sdk_sessions SET custom_title = ?
          WHERE content_session_id = ? AND custom_title IS NULL
        `).run(customTitle, contentSessionId);
      }
      return existing.id;
    }
    this.db.prepare(`
      INSERT INTO sdk_sessions
      (content_session_id, memory_session_id, project, user_prompt, custom_title, started_at, started_at_epoch, status)
      VALUES (?, NULL, ?, ?, ?, ?, ?, 'active')
    `).run(contentSessionId, project, userPrompt, customTitle || null, now.toISOString(), nowEpoch);
    const row = this.db.prepare("SELECT id FROM sdk_sessions WHERE content_session_id = ?").get(contentSessionId);
    return row.id;
  }
  saveUserPrompt(contentSessionId, promptNumber, promptText) {
    const now = new Date;
    const nowEpoch = now.getTime();
    const stmt = this.db.prepare(`
      INSERT INTO user_prompts
      (content_session_id, prompt_number, prompt_text, created_at, created_at_epoch)
      VALUES (?, ?, ?, ?, ?)
    `);
    const result = stmt.run(contentSessionId, promptNumber, promptText, now.toISOString(), nowEpoch);
    return result.lastInsertRowid;
  }
  getUserPrompt(contentSessionId, promptNumber) {
    const stmt = this.db.prepare(`
      SELECT prompt_text
      FROM user_prompts
      WHERE content_session_id = ? AND prompt_number = ?
      LIMIT 1
    `);
    const result = stmt.get(contentSessionId, promptNumber);
    return result?.prompt_text ?? null;
  }
