function formatTimelineForClaudeMd(timelineText) {
  const lines = [];
  lines.push("# Recent Activity");
  lines.push("");
  const apiLines = timelineText.split(`
`);
  const observations = [];
  let lastTimeStr = "";
  let currentDate = null;
  for (const line of apiLines) {
    const dateMatch = line.match(/^###\s+(.+)$/);
    if (dateMatch) {
      const dateStr = dateMatch[1].trim();
      const parsedDate = new Date(dateStr);
      if (!isNaN(parsedDate.getTime())) {
        currentDate = parsedDate;
      }
      continue;
    }
    const match = line.match(/^\|\s*(#[S]?\d+)\s*\|\s*([^|]+)\s*\|\s*([^|]+)\s*\|\s*([^|]+)\s*\|\s*([^|]+)\s*\|/);
    if (match) {
      const [, id, timeStr, typeEmoji, title, tokens] = match;
      let time3;
      if (timeStr.trim() === "″" || timeStr.trim() === '"') {
        time3 = lastTimeStr;
      } else {
        time3 = timeStr.trim();
        lastTimeStr = time3;
      }
      const baseDate = currentDate ? new Date(currentDate) : new Date;
      const timeParts = time3.match(/(\d+):(\d+)\s*(AM|PM)/i);
      let epoch = baseDate.getTime();
      if (timeParts) {
        let hours = parseInt(timeParts[1], 10);
        const minutes = parseInt(timeParts[2], 10);
        const isPM = timeParts[3].toUpperCase() === "PM";
        if (isPM && hours !== 12)
          hours += 12;
        if (!isPM && hours === 12)
          hours = 0;
        baseDate.setHours(hours, minutes, 0, 0);
        epoch = baseDate.getTime();
      }
      observations.push({
        id: id.trim(),
        time: time3,
        typeEmoji: typeEmoji.trim(),
        title: title.trim(),
        tokens: tokens.trim(),
        epoch
      });
    }
  }
  if (observations.length === 0) {
    return "";
  }
  const byDate = groupByDate(observations, (obs) => new Date(obs.epoch).toISOString());
  for (const [day, dayObs] of byDate) {
    lines.push(`### ${day}`);
    lines.push("");
    lines.push("| ID | Time | T | Title | Read |");
    lines.push("|----|------|---|-------|------|");
    let lastTime = "";
    for (const obs of dayObs) {
      const timeDisplay = obs.time === lastTime ? '"' : obs.time;
      lastTime = obs.time;
      lines.push(`| ${obs.id} | ${timeDisplay} | ${obs.typeEmoji} | ${obs.title} | ${obs.tokens} |`);
    }
    lines.push("");
  }
  return lines.join(`
`).trim();
}
