function broadcastObservation(worker, payload) {
  if (!worker?.sseBroadcaster) {
    return;
  }
  worker.sseBroadcaster.broadcast({
    type: "new_observation",
    observation: payload
  });
}
function broadcastSummary(worker, payload) {
  if (!worker?.sseBroadcaster) {
    return;
  }
  worker.sseBroadcaster.broadcast({
    type: "new_summary",
    summary: payload
  });
}

