      logger.debug("SEARCH", "Auto mode: Using observation as timeline anchor", { observationId: topResult.id });
      const timelineData = this.sessionStore.getTimelineAroundObservation(topResult.id, topResult.created_at_epoch, depth_before, depth_after, project);
      const items = [
        ...(timelineData.observations || []).map((obs) => ({ type: "observation", data: obs, epoch: obs.created_at_epoch })),
        ...(timelineData.sessions || []).map((sess) => ({ type: "session", data: sess, epoch: sess.created_at_epoch })),
        ...(timelineData.prompts || []).map((prompt) => ({ type: "prompt", data: prompt, epoch: prompt.created_at_epoch }))
      ];
      items.sort((a, b) => a.epoch - b.epoch);
