// src/services/worker/FormattingService.ts
init_ModeManager();
var CHARS_PER_TOKEN_ESTIMATE3 = 4;

class FormattingService {
  formatSearchTips() {
    return `
---
\uD83D\uDCA1 Search Strategy:
1. Search with index to see titles, dates, IDs
2. Use timeline to get context around interesting results
3. Batch fetch full details: get_observations(ids=[...])

Tips:
• Filter by type: obs_type="bugfix,feature"
• Filter by date: dateStart="2025-01-01"
• Sort: orderBy="date_desc" or "date_asc"`;
  }
  formatTime(epoch) {
    return new Date(epoch).toLocaleString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true
    });
  }
  estimateReadTokens(obs) {
    const size = (obs.title?.length || 0) + (obs.subtitle?.length || 0) + (obs.narrative?.length || 0) + (obs.facts?.length || 0);
    return Math.ceil(size / CHARS_PER_TOKEN_ESTIMATE3);
  }
  formatObservationIndex(obs, _index) {
    const id = `#${obs.id}`;
    const time4 = this.formatTime(obs.created_at_epoch);
    const icon = ModeManager.getInstance().getTypeIcon(obs.type);
    const title = obs.title || "Untitled";
    const readTokens = this.estimateReadTokens(obs);
    const workEmoji = ModeManager.getInstance().getWorkEmoji(obs.type);
    const workTokens = obs.discovery_tokens || 0;
    const workDisplay = workTokens > 0 ? `${workEmoji} ${workTokens}` : "-";
    return `| ${id} | ${time4} | ${icon} | ${title} | ~${readTokens} | ${workDisplay} |`;
  }
  formatSessionIndex(session, _index) {
    const id = `#S${session.id}`;
    const time4 = this.formatTime(session.created_at_epoch);
    const icon = "\uD83C\uDFAF";
    const title = session.request || `Session ${session.memory_session_id?.substring(0, 8) || "unknown"}`;
    return `| ${id} | ${time4} | ${icon} | ${title} | - | - |`;
  }
  formatUserPromptIndex(prompt, _index) {
    const id = `#P${prompt.id}`;
    const time4 = this.formatTime(prompt.created_at_epoch);
    const icon = "\uD83D\uDCAC";
    const title = prompt.prompt_text.length > 60 ? prompt.prompt_text.substring(0, 57) + "..." : prompt.prompt_text;
    return `| ${id} | ${time4} | ${icon} | ${title} | - | - |`;
  }
  formatTableHeader() {
    return `| ID | Time | T | Title | Read | Work |
|-----|------|---|-------|------|------|`;
  }
  formatSearchTableHeader() {
    return `| ID | Time | T | Title | Read |
|----|------|---|-------|------|`;
  }
  formatObservationSearchRow(obs, lastTime) {
    const id = `#${obs.id}`;
    const time4 = this.formatTime(obs.created_at_epoch);
    const icon = ModeManager.getInstance().getTypeIcon(obs.type);
    const title = obs.title || "Untitled";
    const readTokens = this.estimateReadTokens(obs);
    const timeDisplay = time4 === lastTime ? "″" : time4;
    return {
      row: `| ${id} | ${timeDisplay} | ${icon} | ${title} | ~${readTokens} |`,
      time: time4
    };
  }
  formatSessionSearchRow(session, lastTime) {
    const id = `#S${session.id}`;
    const time4 = this.formatTime(session.created_at_epoch);
    const icon = "\uD83C\uDFAF";
    const title = session.request || `Session ${session.memory_session_id?.substring(0, 8) || "unknown"}`;
    const timeDisplay = time4 === lastTime ? "″" : time4;
    return {
      row: `| ${id} | ${timeDisplay} | ${icon} | ${title} | - |`,
      time: time4
    };
  }
  formatUserPromptSearchRow(prompt, lastTime) {
    const id = `#P${prompt.id}`;
    const time4 = this.formatTime(prompt.created_at_epoch);
    const icon = "\uD83D\uDCAC";
    const title = prompt.prompt_text.length > 60 ? prompt.prompt_text.substring(0, 57) + "..." : prompt.prompt_text;
    const timeDisplay = time4 === lastTime ? "″" : time4;
    return {
      row: `| ${id} | ${timeDisplay} | ${icon} | ${title} | - |`,
      time: time4
    };
  }
}

// src/services/worker/TimelineService.ts
init_ModeManager();

class TimelineService {
  buildTimeline(data) {
    const items = [
      ...data.observations.map((obs) => ({ type: "observation", data: obs, epoch: obs.created_at_epoch })),
      ...data.sessions.map((sess) => ({ type: "session", data: sess, epoch: sess.created_at_epoch })),
      ...data.prompts.map((prompt) => ({ type: "prompt", data: prompt, epoch: prompt.created_at_epoch }))
    ];
    items.sort((a, b) => a.epoch - b.epoch);
    return items;
  }
  filterByDepth(items, anchorId, anchorEpoch, depth_before, depth_after) {
    if (items.length === 0)
      return items;
    let anchorIndex = -1;
    if (typeof anchorId === "number") {
      anchorIndex = items.findIndex((item) => item.type === "observation" && item.data.id === anchorId);
    } else if (typeof anchorId === "string" && anchorId.startsWith("S")) {
      const sessionNum = parseInt(anchorId.slice(1), 10);
      anchorIndex = items.findIndex((item) => item.type === "session" && item.data.id === sessionNum);
    } else {
      anchorIndex = items.findIndex((item) => item.epoch >= anchorEpoch);
      if (anchorIndex === -1)
        anchorIndex = items.length - 1;
    }
    if (anchorIndex === -1)
      return items;
    const startIndex = Math.max(0, anchorIndex - depth_before);
    const endIndex = Math.min(items.length, anchorIndex + depth_after + 1);
    return items.slice(startIndex, endIndex);
  }
  formatTimeline(items, anchorId, query2, depth_before, depth_after) {
    if (items.length === 0) {
      return query2 ? `Found observation matching "${query2}", but no timeline context available.` : "No timeline items found";
    }
    const lines = [];
    if (query2 && anchorId) {
      const anchorObs = items.find((item) => item.type === "observation" && item.data.id === anchorId);
      const anchorTitle = anchorObs ? anchorObs.data.title || "Untitled" : "Unknown";
      lines.push(`# Timeline for query: "${query2}"`);
      lines.push(`**Anchor:** Observation #${anchorId} - ${anchorTitle}`);
    } else if (anchorId) {
      lines.push(`# Timeline around anchor: ${anchorId}`);
    } else {
      lines.push(`# Timeline`);
    }
    if (depth_before !== undefined && depth_after !== undefined) {
      lines.push(`**Window:** ${depth_before} records before → ${depth_after} records after | **Items:** ${items.length}`);
    } else {
      lines.push(`**Items:** ${items.length}`);
    }
    lines.push("");
    lines.push(`**Legend:** \uD83C\uDFAF session-request | \uD83D\uDD34 bugfix | \uD83D\uDFE3 feature | \uD83D\uDD04 refactor | ✅ change | \uD83D\uDD35 discovery | \uD83E\uDDE0 decision`);
    lines.push("");
    const dayMap = new Map;
    for (const item of items) {
      const day = this.formatDate(item.epoch);
      if (!dayMap.has(day)) {
        dayMap.set(day, []);
      }
      dayMap.get(day).push(item);
    }
    const sortedDays = Array.from(dayMap.entries()).sort((a, b) => {
      const aDate = new Date(a[0]).getTime();
      const bDate = new Date(b[0]).getTime();
      return aDate - bDate;
    });
    for (const [day, dayItems] of sortedDays) {
      lines.push(`### ${day}`);
      lines.push("");
      let currentFile = null;
      let lastTime = "";
      let tableOpen = false;
      for (const item of dayItems) {
        const isAnchor = typeof anchorId === "number" && item.type === "observation" && item.data.id === anchorId || typeof anchorId === "string" && anchorId.startsWith("S") && item.type === "session" && `S${item.data.id}` === anchorId;
        if (item.type === "session") {
          if (tableOpen) {
            lines.push("");
            tableOpen = false;
            currentFile = null;
            lastTime = "";
          }
          const sess = item.data;
          const title = sess.request || "Session summary";
          const marker = isAnchor ? " ← **ANCHOR**" : "";
          lines.push(`**\uD83C\uDFAF #S${sess.id}** ${title} (${this.formatDateTime(item.epoch)})${marker}`);
          lines.push("");
        } else if (item.type === "prompt") {
          if (tableOpen) {
            lines.push("");
            tableOpen = false;
            currentFile = null;
            lastTime = "";
          }
          const prompt = item.data;
          const truncated = prompt.prompt_text.length > 100 ? prompt.prompt_text.substring(0, 100) + "..." : prompt.prompt_text;
          lines.push(`**\uD83D\uDCAC User Prompt #${prompt.prompt_number}** (${this.formatDateTime(item.epoch)})`);
          lines.push(`> ${truncated}`);
          lines.push("");
        } else if (item.type === "observation") {
          const obs = item.data;
          const file = "General";
          if (file !== currentFile) {
            if (tableOpen) {
              lines.push("");
            }
            lines.push(`**${file}**`);
            lines.push(`| ID | Time | T | Title | Tokens |`);
            lines.push(`|----|------|---|-------|--------|`);
            currentFile = file;
            tableOpen = true;
            lastTime = "";
          }
          const icon = this.getTypeIcon(obs.type);
          const time4 = this.formatTime(item.epoch);
          const title = obs.title || "Untitled";
          const tokens = this.estimateTokens(obs.narrative);
          const showTime = time4 !== lastTime;
          const timeDisplay = showTime ? time4 : "″";
          lastTime = time4;
          const anchorMarker = isAnchor ? " ← **ANCHOR**" : "";
          lines.push(`| #${obs.id} | ${timeDisplay} | ${icon} | ${title}${anchorMarker} | ~${tokens} |`);
        }
      }
      if (tableOpen) {
        lines.push("");
      }
    }
    return lines.join(`
`);
  }
  getTypeIcon(type) {
    return ModeManager.getInstance().getTypeIcon(type);
  }
  formatDate(epochMs) {
    const date5 = new Date(epochMs);
    return date5.toLocaleString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric"
    });
  }
  formatTime(epochMs) {
    const date5 = new Date(epochMs);
    return date5.toLocaleString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true
    });
  }
  formatDateTime(epochMs) {
    const date5 = new Date(epochMs);
    return date5.toLocaleString("en-US", {
      month: "short",
      day: "numeric",
      hour: "numeric",
      minute: "2-digit",
      hour12: true
    });
  }
  estimateTokens(text) {
    if (!text)
      return 0;
    return Math.ceil(text.length / 4);
  }
}

// src/services/worker/events/SessionEventBroadcaster.ts
class SessionEventBroadcaster {
  sseBroadcaster;
  workerService;
  constructor(sseBroadcaster, workerService) {
    this.sseBroadcaster = sseBroadcaster;
    this.workerService = workerService;
  }
  broadcastNewPrompt(prompt) {
    this.sseBroadcaster.broadcast({
      type: "new_prompt",
      prompt
    });
    this.sseBroadcaster.broadcast({
      type: "processing_status",
      isProcessing: true
    });
    this.workerService.broadcastProcessingStatus();
  }
  broadcastSessionStarted(sessionDbId, project) {
    this.sseBroadcaster.broadcast({
      type: "session_started",
      sessionDbId,
      project
    });
    this.workerService.broadcastProcessingStatus();
  }
  broadcastObservationQueued(sessionDbId) {
    this.sseBroadcaster.broadcast({
      type: "observation_queued",
      sessionDbId
    });
    this.workerService.broadcastProcessingStatus();
  }
  broadcastSessionCompleted(sessionDbId) {
    this.sseBroadcaster.broadcast({
      type: "session_completed",
      timestamp: Date.now(),
      sessionDbId
    });
    this.workerService.broadcastProcessingStatus();
  }
  broadcastSummarizeQueued() {
    this.workerService.broadcastProcessingStatus();
  }
}

