// src/utils/tag-stripping.ts
init_logger();
var MAX_TAG_COUNT = 100;
function countTags(content) {
  const privateCount = (content.match(/<private>/g) || []).length;
  const contextCount = (content.match(/<claude-mem-context>/g) || []).length;
  const systemInstructionCount = (content.match(/<system_instruction>/g) || []).length;
  const systemInstructionHyphenCount = (content.match(/<system-instruction>/g) || []).length;
  return privateCount + contextCount + systemInstructionCount + systemInstructionHyphenCount;
}
function stripTagsInternal(content) {
  const tagCount = countTags(content);
  if (tagCount > MAX_TAG_COUNT) {
    logger.warn("SYSTEM", "tag count exceeds limit", undefined, {
      tagCount,
      maxAllowed: MAX_TAG_COUNT,
      contentLength: content.length
    });
  }
  return content.replace(/<claude-mem-context>[\s\S]*?<\/claude-mem-context>/g, "").replace(/<private>[\s\S]*?<\/private>/g, "").replace(/<system_instruction>[\s\S]*?<\/system_instruction>/g, "").replace(/<system-instruction>[\s\S]*?<\/system-instruction>/g, "").trim();
}
function stripMemoryTagsFromJson(content) {
  return stripTagsInternal(content);
}
function stripMemoryTagsFromPrompt(content) {
  return stripTagsInternal(content);
}

// src/services/worker/session/SessionCompletionHandler.ts
class SessionCompletionHandler {
  sessionManager;
  eventBroadcaster;
  constructor(sessionManager, eventBroadcaster) {
    this.sessionManager = sessionManager;
    this.eventBroadcaster = eventBroadcaster;
  }
  async completeByDbId(sessionDbId) {
    await this.sessionManager.deleteSession(sessionDbId);
    this.eventBroadcaster.broadcastSessionCompleted(sessionDbId);
  }
}

// src/services/worker/validation/PrivacyCheckValidator.ts
init_logger();

class PrivacyCheckValidator {
  static checkUserPromptPrivacy(store, contentSessionId, promptNumber, operationType, sessionDbId, additionalContext) {
    const userPrompt = store.getUserPrompt(contentSessionId, promptNumber);
    if (!userPrompt || userPrompt.trim() === "") {
      logger.debug("HOOK", `Skipping ${operationType} - user prompt was entirely private`, {
        sessionId: sessionDbId,
        promptNumber,
        ...additionalContext
      });
      return null;
    }
    return userPrompt;
  }
}

