init_paths();
init_logger();
import path22 from "path";
import { readFileSync as readFileSync19, writeFileSync as writeFileSync8, existsSync as existsSync18, renameSync as renameSync4, mkdirSync as mkdirSync10 } from "fs";
import { homedir as homedir17 } from "os";

